// Decide whether the bot should auto-reply after the 1h cooling-off wait.
// Core guarantee: the SAME inbound can never be answered twice (webhook redelivery,
// re-fired trigger, or a human/teammate stepping in during the wait).
const p = $('pickSeg').first().json;

const botPausedRaw = String(p.bot_paused || '').trim().toLowerCase();
const isPaused = ['true', 'yes', '1', 'y', 'paused'].includes(botPausedRaw);
const calendlySent = String(p.calendly_link_sent || '').trim() !== '';

const SCHED_RE = /(calendly\.com|teams\.microsoft\.com\/meet|zoom\.us|meet\.google)/i;
const isOurs = (it) => {
  const fl = it && it.is_sender;
  return fl === 1 || fl === true || fl === '1' || String(fl).toLowerCase() === 'true';
};
const tsOf = (it) => new Date((it && (it.timestamp || it.date || it.created_at)) || 0).getTime() || 0;
const idOf = (it) => String((it && (it.id || it.message_id || it.provider_id)) || '');

const triggerId = String(p.message_id || '');
const triggerTs = new Date(p.inbound_ts || 0).getTime() || 0;

let teamReplied = false;    // newest message in the thread is from our side
let linkPresent = false;    // a meeting link is already on the table (either side)
let alreadyReplied = false; // we already answered this exact inbound -> dedup
let staleTrigger = false;   // prospect already sent something newer -> let that run handle it
let fetchOK = false;

try {
  const resp = $('fetchLatest').first().json;
  let items = resp.items || resp.messages || resp.data || [];
  if (!Array.isArray(items) && Array.isArray(resp)) items = resp;
  if (Array.isArray(items) && items.length) {
    fetchOK = true;
    const asc = [...items].sort((a, b) => tsOf(a) - tsOf(b));
    linkPresent = asc.some(it => SCHED_RE.test(String(it.text || it.message || '')));
    teamReplied = isOurs(asc[asc.length - 1]);

    // Locate the message that triggered THIS run: prefer id match, else newest inbound at/before triggerTs.
    let idx = triggerId ? asc.findIndex(it => idOf(it) === triggerId) : -1;
    if (idx === -1 && triggerTs) {
      for (let i = asc.length - 1; i >= 0; i--) {
        if (!isOurs(asc[i]) && tsOf(asc[i]) <= triggerTs) { idx = i; break; }
      }
    }
    if (idx !== -1) {
      const after = asc.slice(idx + 1);
      alreadyReplied = after.some(isOurs);             // we already responded after it
      staleTrigger   = after.some(it => !isOurs(it));  // a newer prospect message exists
    } else {
      // Could not locate the trigger in history -> fall back to "we already had the last word".
      alreadyReplied = teamReplied;
    }
  }
} catch (e) {
  fetchOK = false; // fetch failed -> only block on the sheet-derived signals (paused/calendly)
}

const shouldReply = !isPaused && !calendlySent && !teamReplied && !linkPresent && !alreadyReplied && !staleTrigger;
const skip_reason = isPaused ? 'bot_paused'
  : calendlySent ? 'calendly_already_sent'
  : alreadyReplied ? 'already_replied'
  : staleTrigger ? 'superseded_by_newer_inbound'
  : linkPresent ? 'scheduling_link_present'
  : teamReplied ? 'team_replied_manually'
  : '';

return [{ json: { ...p, shouldReply, skip_reason, fetch_ok: fetchOK } }];

// Deterministic safety screen on the agent's draft BEFORE it can be sent.
// Blocks (a) empty drafts, (b) leaked operator/CRM/system text, (c) bot/AI self-reveal,
// (d) hallucinated live actions, (e) credential pastes, (f) phone numbers (HARD RULE).
// On block: safe=false -> the IF routes to a founder alert instead of sending.
const out = ($('message agent').first().json.output) || {};
const msg = String(out.message || '').trim();
const lower = msg.toLowerCase();

const banned = [
  // operator / CRM / system leaks
  'chat id', 'chat_id', 'pipeline', 'crm', 'mapping', 'no reply', 'drafted',
  'source feed', 're-submit', 'resubmit', 'outbound', 'inbound', 'prospect field',
  // bot / AI self-reveal
  'as an ai', 'language model', 'i am a bot', "i'm a bot", 'automated', 'automation',
  // hallucinated live actions
  'letting you in', 'you are in the meeting', "you're in the meeting",
  'connecting now', 'team is connecting', 'joining now',
  'share the meeting details shortly', 'i see you'
];

let block_reason = '';
if (!msg) {
  block_reason = 'empty_message';
}
if (!block_reason) {
  const hit = banned.find(b => lower.includes(b));
  if (hit) block_reason = 'banned_phrase:' + hit;
}
// Credential paste: v2 access is link-based, NEVER paste logins/passwords into a DM.
if (!block_reason) {
  if (/\bpass(?:word|code)\b/i.test(msg) || /\buser\s?name\b/i.test(msg)
      || /\blogin\s*(?:url|portal|id|credential)/i.test(msg) || /\bcredentials?\b/i.test(msg)) {
    block_reason = 'credential_leak';
  }
}
// Phone number: HARD RULE = never share/ask a phone number. Strip URLs first so meeting
// links (which contain long numeric IDs) don't trip the detector.
if (!block_reason) {
  const noUrls = msg.replace(/https?:\/\/\S+/gi, ' ');
  const hit = (noUrls.match(/[+(]?\d[\d\s().\-]{7,}\d/g) || []).find(s => s.replace(/\D/g, '').length >= 10);
  if (hit) block_reason = 'phone_number';
}

const safe = block_reason === '';
return [{ json: { ...$('message agent').first().json, safe, block_reason } }];

